 73→/// Resolve CLI patterns into a list of file paths.
 74→fn resolve_files(cli: &Cli) -> Vec<PathBuf> {
 75→    let mut files = Vec::new();
 76→
 77→    if cli.recursive {
 78→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 79→            vec!["*.jsonl", "agent-*.meta.json"]
 80→        } else {
 81→            cli.globs.iter().map(|s| s.as_str()).collect()
 82→        };
 83→
 84→        // Expand positional patterns as directory globs.
 85→        for pattern in &cli.patterns {
 86→            let dirs: Vec<PathBuf> = match glob::glob(pattern) {
 87→                Ok(paths) => paths
 88→                    .filter_map(|p| p.ok())
 89→                    .filter(|p| p.is_dir())
 90→                    .collect(),
 91→                Err(e) => {
 92→                    eprintln!("Bad pattern {pattern:?}: {e}");
 93→                    std::process::exit(1);
 94→                }
 95→            };
 96→            if dirs.is_empty() {
 97→                eprintln!("No directories match {pattern:?}");
 98→                std::process::exit(1);
 99→            }
100→            for dir in &dirs {
101→                for fg in &file_globs {
102→                    let full = format!("{}/**/{fg}", dir.display());
103→                    match glob::glob(&full) {
104→                        Ok(paths) => {
105→                            for entry in paths.flatten() {
106→                                if entry.is_file() {
107→                                    files.push(entry);
108→                                }
109→                            }
110→                        }
111→                        Err(e) => {
112→                            eprintln!("Bad glob {full:?}: {e}");
113→                            std::process::exit(1);
114→                        }
115→                    }
116→                }
117→            }
118→        }
119→    } else {
120→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
121→            vec!["*.jsonl", "agent-*.meta.json"]
122→        } else {
123→            cli.globs.iter().map(|s| s.as_str()).collect()
124→        };
125→
126→        for pattern in &cli.patterns {
127→            // Check if pattern is a literal directory path first.
128→            let path = PathBuf::from(pattern);
129→            if path.is_dir() {
130→                // Directory: expand file globs inside it (non-recursive).
131→                for fg in &file_globs {
132→                    let full = format!("{}/{fg}", path.display());
133→                    match glob::glob(&full) {
134→                        Ok(paths) => {
135→                            for entry in paths.flatten() {
136→                                if entry.is_file() {
137→                                    files.push(entry);
138→                                }
139→                            }
140→                        }
141→                        Err(e) => {
142→                            eprintln!("Bad glob {full:?}: {e}");
143→                            std::process::exit(1);
144→                        }
145→                    }
146→                }
147→            } else {
148→                // Treat as file glob pattern.
149→                match glob::glob(pattern) {
150→                    Ok(paths) => {
151→                        let mut matched = Vec::new();
152→                        for entry in paths.flatten() {
153→                            if entry.is_file() {
154→                                matched.push(entry);
155→                            } else if entry.is_dir() {
156→                                // Glob matched a directory: expand file
157→                                // globs inside it (non-recursive).
158→                                for fg in &file_globs {
159→                                    let full = format!("{}/{fg}", entry.display());
160→                                    if let Ok(inner) = glob::glob(&full) {
161→                                        for f in inner.flatten() {
162→                                            if f.is_file() {
163→                                                matched.push(f);
164→                                            }
165→                                        }
166→                                    }
167→                                }
168→                            }
169→                        }
170→                        if matched.is_empty() {
171→                            eprintln!("No files match {pattern:?}");
172→                            std::process::exit(1);
173→                        }
174→                        files.extend(matched);
175→                    }
176→                    Err(e) => {
177→                        eprintln!("Bad pattern {pattern:?}: {e}");
178→                        std::process::exit(1);
179→                    }
180→                }
181→            }
182→        }
183→    }
184→
185→    files.sort();
186→    files.dedup();
187→    files
188→}
