190→/// Key for grouping errors: the serde error message + record type.
191→#[derive(Hash, Eq, PartialEq)]
192→struct ErrorKey {
193→    message: String,
194→    record_type: String,
195→}
196→
197→/// A single file:line occurrence of an error.
198→struct ErrorHit {
199→    path: String,
200→    line: usize,
201→}
202→
203→/// Tracks one group of identical errors across files.
204→struct ErrorGroup {
205→    count: usize,
206→    /// How many distinct files contain this error.
207→    file_count: usize,
208→    /// Track which files we've seen (by index) to count distinct files.
209→    seen_files: Vec<usize>,
210→    /// All file:line occurrences (one per distinct file).
211→    hits: Vec<ErrorHit>,
212→}
213→
214→/// Stats returned by `show_transcript`.
215→#[derive(Debug, PartialEq)]
216→struct ShowStats {
217→    shown: usize,
218→    thinking_only: usize,
219→    thinking_empty: usize,
220→    skipped: usize,
221→    parse_errors: usize,
222→}
223→
224→/// Render a session transcript to `out`, returning stats.
225→fn show_transcript_to(reader: impl BufRead, out: &mut impl std::io::Write) -> ShowStats {
226→    let mut stats = ShowStats {
227→        shown: 0,
228→        thinking_only: 0,
229→        thinking_empty: 0,
230→        skipped: 0,
231→        parse_errors: 0,
232→    };
233→
234→    for line in reader.lines() {
235→        let line = line.unwrap_or_default();
236→        if line.trim().is_empty() {
237→            continue;
238→        }
239→        let record: Record = match serde_json::from_str(&line) {
240→            Ok(r) => r,
241→            Err(_) => {
242→                stats.parse_errors += 1;
243→                continue;
244→            }
245→        };
246→        match record {
247→            Record::User(user_rec) => {
248→                if stats.shown > 0 {
249→                    writeln!(out, "---------").unwrap();
250→                }
251→                writeln!(out, "--- user ---").unwrap();
252→                match user_rec.message.content {
253→                    UserContent::Text(text) => writeln!(out, "{text}").unwrap(),
254→                    UserContent::Blocks(blocks) => {
255→                        for block in blocks {
256→                            match block {
257→                                UserContentBlock::Text { text } => {
258→                                    writeln!(out, "{text}").unwrap();
259→                                }
260→                                UserContentBlock::ToolResult { .. } => {
261→                                    writeln!(out, "[tool_result]").unwrap();
262→                                }
263→                            }
264→                        }
265→                    }
266→                }
267→                stats.shown += 1;
268→            }
269→            Record::Assistant(asst_rec) => {
270→                // Collect visible content; skip records with only thinking blocks.
271→                let mut lines = Vec::new();
272→                let mut has_thinking = false;
273→                let mut has_empty_thinking = false;
274→                for block in &asst_rec.message.content {
275→                    match block {
276→                        AssistantContentBlock::Text { text } => lines.push(text.clone()),
277→                        AssistantContentBlock::ToolUse { name, .. } => {
278→                            lines.push(format!("[tool: {name}]"));
279→                        }
280→                        AssistantContentBlock::Thinking { thinking, .. } => {
281→                            has_thinking = true;
282→                            if thinking.is_empty() {
283→                                has_empty_thinking = true;
284→                            }
285→                        }
286→                    }
287→                }
288→                if has_thinking && has_empty_thinking {
289→                    stats.thinking_empty += 1;
290→                }
291→                if lines.is_empty() {
292→                    stats.thinking_only += 1;
293→                    continue;
294→                }
295→                if stats.shown > 0 {
296→                    writeln!(out, "---------").unwrap();
297→                }
298→                writeln!(out, "--- assistant ---").unwrap();
299→                for line in &lines {
300→                    writeln!(out, "{line}").unwrap();
301→                }
302→                stats.shown += 1;
303→            }
304→            _ => {
305→                stats.skipped += 1;
306→            }
307→        }
308→    }
309→
310→    stats
311→}
312→
313→/// Display a session transcript to stdout.
314→fn show_transcript(path: &PathBuf) {
315→    let file = File::open(path).unwrap_or_else(|e| {
316→        eprintln!("Error opening {}: {e}", path.display());
317→        std::process::exit(1);
318→    });
319→    let reader = BufReader::new(file);
320→    let mut out = std::io::stdout().lock();
321→    let stats = show_transcript_to(reader, &mut out);
322→
323→    writeln!(out).unwrap();
324→    writeln!(
325→        out,
326→        "Show summary: {} shown, {} thinking-only ({} empty), {} skipped, {} errors",
327→        stats.shown, stats.thinking_only, stats.thinking_empty, stats.skipped, stats.parse_errors
328→    )
329→    .unwrap();
330→}
