332→fn main() {
333→    let total_start_time = std::time::Instant::now();
334→
335→    println!("main: entered");
336→
337→    println!("main: parsing args... ");
338→    let mut start_time = std::time::Instant::now();
339→    let cli = Cli::parse();
340→    let mut elapsed_time = start_time.elapsed();
341→    println!("main: parsing (took {elapsed_time:?})");
342→
343→    println!("main: resolving files... ");
344→    start_time = std::time::Instant::now();
345→    let files = resolve_files(&cli);
346→    elapsed_time = start_time.elapsed();
347→    println!("main: resolving {} files (took {elapsed_time:?})", files.len());
348→
349→    if files.is_empty() {
350→        eprintln!("No files to process");
351→        std::process::exit(1);
352→    }
353→
354→
355→    println!("main: processing files...");
356→    let mut start_time = std::time::Instant::now();
357→    if cli.show {
358→        if files.len() > 1 {
359→            eprintln!("--show requires a single file, got {}", files.len());
360→            std::process::exit(1);
361→        }
362→        show_transcript(&files[0]);
363→        return;
364→    }
365→
366→    let mut total_records: usize = 0;
367→    let mut total_errors: usize = 0;
368→    let mut total_skipped: usize = 0;
369→    let mut total_empty: usize = 0;
370→    let mut skipped_files: Vec<String> = Vec::new();
371→    let mut empty_files: Vec<String> = Vec::new();
372→    let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();
373→    let mut valid_header_printed = false;
374→
375→    for (file_idx, path) in files.iter().enumerate() {
376→        let file = File::open(path).unwrap_or_else(|e| {
377→            eprintln!("Error opening {}: {e}", path.display());
378→            std::process::exit(1);
379→        });
380→
381→        let filename = path
382→            .file_name()
383→            .map(|f| f.to_string_lossy().into_owned())
384→            .unwrap_or_else(|| path.display().to_string());
385→
386→        // Handle .meta.json files as single-object JSON (not JSONL).
387→        if filename.ends_with(".meta.json") {
388→            let metadata = file.metadata().ok();
389→            if metadata.as_ref().is_some_and(|m| m.len() == 0) {
390→                total_empty += 1;
391→                if cli.zero {
392→                    empty_files.push(path.display().to_string());
393→                }
394→                continue;
395→            }
396→            let result: Result<AgentMeta, _> = serde_json::from_reader(file);
397→            match result {
398→                Ok(_meta) => {
399→                    total_records += 1;
400→                    if cli.valid {
401→                        if !valid_header_printed {
402→                            println!("Valid:");
403→                            valid_header_printed = true;
404→                        }
405→                        println!("  {}", path.display());
406→                        println!("    agent-meta (ok)");
407→                    }
408→                }
409→                Err(e) => {
410→                    total_errors += 1;
411→                    let key = ErrorKey {
412→                        message: format!("{e}"),
413→                        record_type: "agent-meta".to_string(),
414→                    };
415→                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
416→                        count: 0,
417→                        file_count: 0,
418→                        seen_files: Vec::new(),
419→                        hits: Vec::new(),
420→                    });
421→                    group.count += 1;
422→                    if !group.seen_files.contains(&file_idx) {
423→                        group.seen_files.push(file_idx);
424→                        group.file_count += 1;
425→                        group.hits.push(ErrorHit {
426→                            path: path.display().to_string(),
427→                            line: 1,
428→                        });
429→                    }
430→                    if cli.valid {
431→                        if !valid_header_printed {
432→                            println!("Valid:");
433→                            valid_header_printed = true;
434→                        }
435→                        println!("  {}", path.display());
436→                        println!("    agent-meta (error)");
437→                    }
438→                }
439→            }
440→            continue;
441→        }
442→
443→        let mut reader = BufReader::new(file);
444→
445→        // Check for empty files before the sniff test.
446→        let mut first_line = String::new();
447→        if reader.read_line(&mut first_line).unwrap_or(0) == 0 {
448→            total_empty += 1;
449→            if cli.zero {
450→                empty_files.push(path.display().to_string());
451→            }
452→            continue;
453→        }
454→
455→        // First-line sniff test: skip .jsonl files that don't look like
456→        // Claude Code sessions. CCS files start with {"type": or {"parentUuid":.
457→        let trimmed = first_line.trim();
458→        if !trimmed.starts_with("{\"type\":") && !trimmed.starts_with("{\"parentUuid\":") {
459→            total_skipped += 1;
460→            if cli.skipped {
461→                skipped_files.push(path.display().to_string());
462→            }
463→            continue;
464→        }
465→
466→        // Process lines starting from the first line we already read.
467→        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
468→        let mut file_errors: usize = 0;
469→
470→        // Process first line, then remaining lines.
471→        let remaining_lines = reader.lines().map(|l| l.unwrap_or_default());
472→        let all_lines = std::iter::once(first_line.trim_end().to_string()).chain(remaining_lines);
473→
474→        for (i, line) in all_lines.enumerate() {
475→            if line.trim().is_empty() {
476→                continue;
477→            }
478→            match serde_json::from_str::<Record>(&line) {
479→                Ok(record) => {
480→                    *counts.entry(record.label()).or_insert(0) += 1;
481→                }
482→                Err(e) => {
483→                    file_errors += 1;
484→                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
485→                        .ok()
486→                        .and_then(|v| v.get("type")?.as_str().map(String::from))
487→                        .unwrap_or_else(|| "unknown".to_string());
488→
489→                    let key = ErrorKey {
490→                        message: format!("{e}"),
491→                        record_type,
492→                    };
493→                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
494→                        count: 0,
495→                        file_count: 0,
496→                        seen_files: Vec::new(),
497→                        hits: Vec::new(),
498→                    });
499→                    group.count += 1;
500→                    if !group.seen_files.contains(&file_idx) {
501→                        group.seen_files.push(file_idx);
502→                        group.file_count += 1;
503→                        group.hits.push(ErrorHit {
504→                            path: path.display().to_string(),
505→                            line: i + 1,
506→                        });
507→                    }
508→                }
509→            }
510→        }
511→
512→        let file_total: usize = counts.values().sum();
513→        total_records += file_total;
514→        total_errors += file_errors;
515→
516→        if cli.valid {
517→            if !valid_header_printed {
518→                println!("Valid:");
519→                valid_header_printed = true;
520→            }
521→            let mut parts = vec![
522→                format!("errors: {file_errors}"),
523→                format!("records: {file_total}"),
524→            ];
525→            for (label, count) in &counts {
526→                parts.push(format!("{label}: {count}"));
527→            }
528→            println!("  {}", path.display());
529→            println!("    {}", parts.join(", "));
530→        }
531→    }
532→    elapsed_time = start_time.elapsed();
533→    println!("main: file processing complete (took {elapsed_time:?})");
534→
535→    println!("main: summarizing results...");
536→    start_time = std::time::Instant::now();
537→    let file_count = files.len();
538→    let processed = file_count - total_skipped - total_empty;
539→
540→    if valid_header_printed {
541→        println!();
542→    }
543→
544→    let show_errors = cli.errors || cli.error_summary;
545→    if show_errors && !error_groups.is_empty() {
546→        let mut groups: Vec<_> = error_groups.iter().collect();
547→        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
548→
549→        if cli.error_summary && cli.errors {
550→            // -e -E combined: grouped summary with all paths nested
551→            println!("Error summary:");
552→            for (key, group) in &groups {
553→                println!("  {}x {} in {}", group.count, key.message, key.record_type,);
554→                for hit in &group.hits {
555→                    println!("    {}:{}", hit.path, hit.line);
556→                }
557→            }
558→            println!();
559→        } else if cli.error_summary {
560→            // -E only: grouped summary, two lines per group
561→            println!("Error summary:");
562→            for (key, group) in &groups {
563→                let first = &group.hits[0];
564→                println!("  {}x {} in {}", group.count, key.message, key.record_type,);
565→                println!(
566→                    "    {} file(s), first: {}:{}",
567→                    group.file_count, first.path, first.line,
568→                );
569→            }
570→            println!();
571→        } else if cli.errors {
572→            // -e only: flat list of all error file:line paths
573→            println!("Errors:");
574→            let mut all_hits: Vec<_> = error_groups.values().flat_map(|g| g.hits.iter()).collect();
575→            all_hits.sort_by(|a, b| a.path.cmp(&b.path).then(a.line.cmp(&b.line)));
576→            for hit in all_hits {
577→                println!("  {}:{}", hit.path, hit.line);
578→            }
579→            println!();
580→        }
581→    }
582→
583→    if cli.skipped && !skipped_files.is_empty() {
584→        println!("Skipped:");
585→        for f in &skipped_files {
586→            println!("  {f}");
587→        }
588→        println!();
589→    }
590→
591→    if cli.zero && !empty_files.is_empty() {
592→        println!("Zero-len:");
593→        for f in &empty_files {
594→            println!("  {f}");
595→        }
596→        println!();
597→    }
598→
599→    let total_files = processed + total_skipped + total_empty;
600→    println!(
601→        "Summary: {total_files} total files, {processed} valid files with {total_records} records, {total_empty} zero-len, {total_skipped} skipped, {total_errors} errors"
602→    );
603→
604→    if cli.strict && total_errors > 0 {
605→        std::process::exit(2);
606→    }
607→    elapsed_time = start_time.elapsed();
608→    println!("main: summarization complete (took {elapsed_time:?})",);
609→
610→    let total_elapsed_time = total_start_time.elapsed();
611→    println!("main: exiting with code 0 (took {total_elapsed_time:?})");
612→}
