pub struct Timed {
    label: &'static str,
    start: std::time::Instant,
    silent: bool,
}

impl Timed {
    pub fn new(label: &'static str) -> Self {
        Self {
            label,
            start: std::time::Instant::now(),
            silent: false,
        }
    }

    pub fn print(&mut self) {
        eprintln!("{}: {:?}", self.label, self.start.elapsed());
        self.silent = true;
    }

    #[allow(unused)]
    pub fn get(&mut self) -> std::time::Duration {
        self.silent = true;
        self.start.elapsed()
    }
}

impl Drop for Timed {
    fn drop(&mut self) {
        if !self.silent {
            eprintln!("{}: {:?}", self.label, self.start.elapsed());
        }
    }
}

macro_rules! timed {
    ($label:expr, { $($body:tt)* }) => {
        let mut _timer = $crate::timed::Timed::new($label);
        $($body)*
        _timer.print();
    };
}

macro_rules! timed_new {
    ($label:expr) => {
        let mut _timer = $crate::timed::Timed::new($label);
    };
}

pub(crate) use timed;
pub(crate) use timed_new;

