pub struct Timed {
    label: &'static str,
    start: std::time::Instant,
    silent: bool,
}

impl Timed {
    pub fn new(label: &'static str) -> Self {
        Self {
            label,
            start: std::time::Instant::now(),
            silent: false,
        }
    }

    pub fn eprintln(&mut self) {
        eprintln!("{}: {:?}", self.label, self.start.elapsed());
        self.silent = true;
    }

    pub fn print(&mut self) {
        self.eprintln();
    }

    #[allow(unused)]
    pub fn get(&mut self) -> std::time::Duration {
        self.silent = true;
        self.start.elapsed()
    }
}

impl Drop for Timed {
    fn drop(&mut self) {
        if !self.silent {
            self.eprintln();
        }
    }
}

macro_rules! timed {
    ($label:expr) => {
        let _timer = $crate::timed::Timed::new($label);
    };
    ($label:expr, { $($body:tt)* }) => {
        let mut _timer = $crate::timed::Timed::new($label);
        $($body)*
        _timer.print();
    };
}

pub(crate) use timed;

