            start: std::time::Instant::now(),
            silent: false,
        }
    }

    pub fn get(&mut self) -> std::time::Duration {
        self.silent = true;
        self.start.elapsed()
    }

    pub fn println(&mut self) {
        let elapsed = self.get();
        println!("{} {:?}", self.label, elapsed);
